close">)</span></span></span></span>为</p>
<p v-pre class='katex-block'><span class="katex-display"><span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML" display="block"><semantics><mtable rowspacing="0.25em" columnalign="right left" columnspacing="0em"><mtr><mtd class ="mtr-glue"></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow><mi>f</mi><mo stretchy="false">(</mo><mi>p</mi><mo stretchy="false">)</mo></mrow></mstyle></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow><mrow></mrow><mo>=</mo><munderover><mo>∑</mo><mrow><msub><mi>n</mi><mn>1</mn></msub><mo>=</mo><mn>0</mn></mrow><mi>N</mi></munderover><msubsup><mi>n</mi><mn>1</mn><mn>2</mn></msubsup><mo>⋅</mo><msubsup><mi>C</mi><mi>N</mi><msub><mi>n</mi><mn>1</mn></msub></msubsup><msup><mi>p</mi><msub><mi>n</mi><mn>1</mn></msub></msup><msup><mi>q</mi><mrow><mi>N</mi><mo>−</mo><msub><mi>n</mi><mn>1</mn></msub></mrow></msup></mrow></mstyle></mtd><mtd class ="mtr-glue"></mtd><mtd class ="mml-eqn-num"></mtd></mtr><mtr><mtd class ="mtr-glue"></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow></mrow></mstyle></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow><mrow></mrow><mo>=</mo><munderover><mo>∑</mo><mrow><msub><mi>n</mi><mn>1</mn></msub><mo>=</mo><mn>0</mn></mrow><mi>N</mi></munderover><msubsup><mi>C</mi><mi>N</mi><msub><mi>n</mi><mn>1</mn></msub></msubsup><mo fence="false" stretchy="true" minsize="1.2em" maxsize="1.2em">(</mo><msub><mi>n</mi><mn>1</mn></msub><msup><mi>p</mi><msub><mi>n</mi><mn>1</mn></msub></msup><mo>+</mo><msup><mi>p</mi><mn>2</mn></msup><mo stretchy="false">(</mo><mfrac><mi mathvariant="normal">∂</mi><mrow><mi mathvariant="normal">∂</mi><mi>p</mi></mrow></mfrac><msup><mo stretchy="false">)</mo><mn>2</mn></msup><msup><mi>p</mi><msub><mi>n</mi><mn>1</mn></msub></msup><mo fence="false" stretchy="true" minsize="1.2em" maxsize="1.2em">)</mo><msup><mi>q</mi><mrow><mi>N</mi><mo>−</mo><msub><mi>n</mi><mn>1</mn></msub></mrow></msup></mrow></mstyle></mtd><mtd class ="mtr-glue"></mtd><mtd class ="mml-eqn-num"></mtd></mtr><mtr><mtd class ="mtr-glue"></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow></mrow></mstyle></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow><mrow></mrow><mo>=</mo><mover accent="true"><msub><mi>n</mi><mn>1</mn></msub><mo stretchy="true">‾</mo></mover><mo>+</mo><msup><mi>p</mi><mn>2</mn></msup><mo stretchy="false">(</mo><mfrac><mi mathvariant="normal">∂</mi><mrow><mi mathvariant="normal">∂</mi><mi>p</mi></mrow></mfrac><msup><mo stretchy="false">)</mo><mn>2</mn></msup><mo stretchy="false">(</mo><mi>p</mi><mo>+</mo><mi>q</mi><msup><mo stretchy="false">)</mo><mi>N</mi></msup></mrow></mstyle></mtd><mtd class ="mtr-glue"></mtd><mtd class ="mml-eqn-num"></mtd></mtr><mtr><mtd class ="mtr-glue"></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow></mrow></mstyle></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow><mrow></mrow><mo>=</mo><mover accent="true"><msub><mi>n</mi><mn>1</mn></msub><mo stretchy="true">‾</mo></mover><mo>+</mo><msup><mi>p</mi><mn>2</mn></msup><mi>N</mi><mo stretchy="false">(</mo><mi>N</mi><mo>−</mo><mn>1</mn><mo stretchy="false">)</mo><mo stretchy="false">(</mo><mi>p</mi><mo>+</mo><mi>q</mi><msup><mo stretchy="false">)</mo><mrow><mi>N</mi><mo>−</mo><mn>2</mn></mrow></msup></mrow></mstyle></mtd><mtd class ="mtr-glue"></mtd><mtd class ="mml-eqn-num"></mtd></mtr></mtable><annotation encoding="application/x-tex">
\begin{align}
f(p)&amp;=\sum_{n_1=0}^N n_1^2 \cdot C_N^{n_1}p^{n_1}q^{N-n_1}\\
&amp;=\sum_{n_1=0}^N C_N^{n_1}\big (n_1p^{n_1}+p^2(\cfrac {\partial}{\partial p})^2p^{n_1}\big )q^{N-n_1}\\
&amp;=\overline {n_1}+p^2(\cfrac {\partial}{\partial p})^2(p+q)^N\\
&amp;=\overline {n_1}+p^2N(N-1)(p+q)^{N-2}
\end{align}

