<p v-pre class='katex-block'><span class="katex-display"><span class="katex"><span class="katex-mathml"><math xmlns="http://www.w3.org/1998/Math/MathML" display="block"><semantics><mtable rowspacing="0.25em" columnalign="right left" columnspacing="0em"><mtr><mtd class ="mtr-glue"></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow><mi>f</mi><mo stretchy="false">(</mo><mi>p</mi><mo stretchy="false">)</mo></mrow></mstyle></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow><mrow></mrow><mo>=</mo><munderover><mo>∑</mo><mrow><msub><mi>n</mi><mn>1</mn></msub><mo>=</mo><mn>0</mn></mrow><mi>N</mi></munderover><msubsup><mi>n</mi><mn>1</mn><mn>2</mn></msubsup><mo>⋅</mo><msubsup><mi>C</mi><mi>N</mi><msub><mi>n</mi><mn>1</mn></msub></msubsup><msup><mi>p</mi><msub><mi>n</mi><mn>1</mn></msub></msup><msup><mi>q</mi><mrow><mi>N</mi><mo>−</mo><msub><mi>n</mi><mn>1</mn></msub></mrow></msup></mrow></mstyle></mtd><mtd class ="mtr-glue"></mtd><mtd class ="mml-eqn-num"></mtd></mtr><mtr><mtd class ="mtr-glue"></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow></mrow></mstyle></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow><mrow></mrow><mo>=</mo><mo stretchy="false">(</mo><mi>p</mi><mfrac><mi mathvariant="normal">∂</mi><mrow><mi mathvariant="normal">∂</mi><mi>p</mi></mrow></mfrac><mo stretchy="false">)</mo><munderover><mo>∑</mo><mrow><msub><mi>n</mi><mn>1</mn></msub><mo>=</mo><mn>0</mn></mrow><mi>N</mi></munderover><msubsup><mi>C</mi><mi>N</mi><msub><mi>n</mi><mn>1</mn></msub></msubsup><msub><mi>n</mi><mn>1</mn></msub><msup><mi>p</mi><msub><mi>n</mi><mn>1</mn></msub></msup><msup><mi>q</mi><mrow><mi>N</mi><mo>−</mo><msub><mi>n</mi><mn>1</mn></msub></mrow></msup></mrow></mstyle></mtd><mtd class ="mtr-glue"></mtd><mtd class ="mml-eqn-num"></mtd></mtr><mtr><mtd class ="mtr-glue"></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow></mrow></mstyle></mtd><mtd><mstyle scriptlevel="0" displaystyle="true"><mrow><mrow></mrow><mo>=</mo><mo stretchy="fa